mapper.select:
SELECT su.*, sd.*
FROM sys_user su
         JOIN sys_user_dept sud on su.user_id = sud.user_id
         JOIN sys_dept sd on sud.dept_id = sd.dept_id
WHERE sd.dept_id = #{deptId}
   OR find_in_set(sd.dept_id, (select ancestors from sys_dept where dept_id = #{deptId} Limit 1));

SELECT su.*, sd.*
FROM sys_user su
         JOIN sys_user_dept sud on su.user_id = sud.user_id
         JOIN sys_dept sd on sud.dept_id = sd.dept_id
WHERE sd.dept_id = #{deptId}
   OR find_in_set(#{deptId}, sd.ancestors);

SELECT su.*, sd.*
FROM sys_user su
         JOIN sys_user_dept sud on su.user_id = sud.user_id
         JOIN sys_dept sd on sud.dept_id = sd.dept_id
WHERE sd.dept_code = #{deptCode}
   OR find_in_set(sd.dept_id, (select ancestors from sys_dept where dept_code = #{deptCode} Limit 1));
